const e=JSON.parse('{"key":"v-78890a56","path":"/threejs/%E6%9D%90%E8%B4%A8/%E7%82%B9%E7%B2%BE%E7%81%B5%E6%9D%90%E8%B4%A8.html","title":"SpriteMaterial(点精灵材质)","lang":"zh-CN","frontmatter":{"title":"SpriteMaterial(点精灵材质)","icon":"markdown","order":16,"date":"2023-03-13T00:00:00.000Z","category":["threejs"],"tag":["材质"],"description":"# SpriteMaterial 一种使用Sprite的材质。 # 构造器 # parameters : Object parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性) 属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色）， 内部调用Color.set(color)。 SpriteMaterials不会被Material.clippingPlanes裁剪。 # 属性 共有属性请参见其基类Material # .alphaMap : Texture alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。 仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。 # .color : Color 材质的颜色(Color)，默认值为白色 (0xffffff)。 .map会和 color 相乘。 # .fog : Boolean 材质是否受雾影响。默认为true。 # .isSpriteMaterial : Boolean Read-only标志，用于检查给定对象是否为SpriteMaterial类型。 # .map : Texture 颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。 # .rotation : Radians sprite的转动，以弧度为单位。默认值为0。 # .sizeAttenuation : Boolean 精灵的大小是否会被相机深度衰减。（仅限透视摄像头。）默认为true。 # .transparent : Boolean 定义此材质是否透明。默认值为 true。 # 方法 共有方法请参见其基类Material","head":[["meta",{"property":"og:url","content":"https://luotianxu1.github.io/threejs/%E6%9D%90%E8%B4%A8/%E7%82%B9%E7%B2%BE%E7%81%B5%E6%9D%90%E8%B4%A8.html"}],["meta",{"property":"og:title","content":"SpriteMaterial(点精灵材质)"}],["meta",{"property":"og:description","content":"# SpriteMaterial 一种使用Sprite的材质。 # 构造器 # parameters : Object parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性) 属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色）， 内部调用Color.set(color)。 SpriteMaterials不会被Material.clippingPlanes裁剪。 # 属性 共有属性请参见其基类Material # .alphaMap : Texture alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。 仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。 # .color : Color 材质的颜色(Color)，默认值为白色 (0xffffff)。 .map会和 color 相乘。 # .fog : Boolean 材质是否受雾影响。默认为true。 # .isSpriteMaterial : Boolean Read-only标志，用于检查给定对象是否为SpriteMaterial类型。 # .map : Texture 颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。 # .rotation : Radians sprite的转动，以弧度为单位。默认值为0。 # .sizeAttenuation : Boolean 精灵的大小是否会被相机深度衰减。（仅限透视摄像头。）默认为true。 # .transparent : Boolean 定义此材质是否透明。默认值为 true。 # 方法 共有方法请参见其基类Material"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-13T08:16:22.000Z"}],["meta",{"property":"article:tag","content":"材质"}],["meta",{"property":"article:published_time","content":"2023-03-13T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-13T08:16:22.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"SpriteMaterial(点精灵材质)\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-03-13T00:00:00.000Z\\",\\"dateModified\\":\\"2023-03-13T08:16:22.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"SpriteMaterial","slug":"spritematerial","link":"#spritematerial","children":[]},{"level":2,"title":"构造器","slug":"构造器","link":"#构造器","children":[{"level":3,"title":"parameters : Object","slug":"parameters-object","link":"#parameters-object","children":[]}]},{"level":2,"title":"属性","slug":"属性","link":"#属性","children":[{"level":3,"title":".alphaMap : Texture","slug":"alphamap-texture","link":"#alphamap-texture","children":[]},{"level":3,"title":".color : Color","slug":"color-color","link":"#color-color","children":[]},{"level":3,"title":".fog : Boolean","slug":"fog-boolean","link":"#fog-boolean","children":[]},{"level":3,"title":".isSpriteMaterial : Boolean","slug":"isspritematerial-boolean","link":"#isspritematerial-boolean","children":[]},{"level":3,"title":".map : Texture","slug":"map-texture","link":"#map-texture","children":[]},{"level":3,"title":".rotation : Radians","slug":"rotation-radians","link":"#rotation-radians","children":[]},{"level":3,"title":".sizeAttenuation : Boolean","slug":"sizeattenuation-boolean","link":"#sizeattenuation-boolean","children":[]},{"level":3,"title":".transparent : Boolean","slug":"transparent-boolean","link":"#transparent-boolean","children":[]}]},{"level":2,"title":"方法","slug":"方法","link":"#方法","children":[]}],"git":{"createdTime":1678695382000,"updatedTime":1678695382000,"contributors":[{"name":"Luotianxu","email":"1265062404@qq.com","commits":1}]},"readingTime":{"minutes":1.41,"words":424},"filePathRelative":"threejs/材质/点精灵材质.md","localizedDate":"2023年3月13日","excerpt":"<iframe url=\\"https://luotainxu-demo.netlify.app/#/threejs/spriteMaterial\\">\\n<h2 id=\\"spritematerial\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#spritematerial\\" aria-hidden=\\"true\\">#</a> SpriteMaterial</h2>\\n<p>一种使用Sprite的材质。</p>\\n<h2 id=\\"构造器\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#构造器\\" aria-hidden=\\"true\\">#</a> 构造器</h2>\\n<h3 id=\\"parameters-object\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#parameters-object\\" aria-hidden=\\"true\\">#</a> parameters : Object</h3>\\n<p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p>\\n<p>属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色）， 内部调用Color.set(color)。 SpriteMaterials不会被Material.clippingPlanes裁剪。</p>\\n<h2 id=\\"属性\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#属性\\" aria-hidden=\\"true\\">#</a> 属性</h2>\\n<p>共有属性请参见其基类Material</p>\\n<h3 id=\\"alphamap-texture\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#alphamap-texture\\" aria-hidden=\\"true\\">#</a> .alphaMap : Texture</h3>\\n<p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。</p>\\n<p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。</p>\\n<h3 id=\\"color-color\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#color-color\\" aria-hidden=\\"true\\">#</a> .color : Color</h3>\\n<p>材质的颜色(Color)，默认值为白色 (0xffffff)。 .map会和 color 相乘。</p>\\n<h3 id=\\"fog-boolean\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#fog-boolean\\" aria-hidden=\\"true\\">#</a> .fog : Boolean</h3>\\n<p>材质是否受雾影响。默认为true。</p>\\n<h3 id=\\"isspritematerial-boolean\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#isspritematerial-boolean\\" aria-hidden=\\"true\\">#</a> .isSpriteMaterial : Boolean</h3>\\n<p>Read-only标志，用于检查给定对象是否为SpriteMaterial类型。</p>\\n<h3 id=\\"map-texture\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#map-texture\\" aria-hidden=\\"true\\">#</a> .map : Texture</h3>\\n<p>颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。</p>\\n<h3 id=\\"rotation-radians\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#rotation-radians\\" aria-hidden=\\"true\\">#</a> .rotation : Radians</h3>\\n<p>sprite的转动，以弧度为单位。默认值为0。</p>\\n<h3 id=\\"sizeattenuation-boolean\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#sizeattenuation-boolean\\" aria-hidden=\\"true\\">#</a> .sizeAttenuation : Boolean</h3>\\n<p>精灵的大小是否会被相机深度衰减。（仅限透视摄像头。）默认为true。</p>\\n<h3 id=\\"transparent-boolean\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#transparent-boolean\\" aria-hidden=\\"true\\">#</a> .transparent : Boolean</h3>\\n<p>定义此材质是否透明。默认值为 true。</p>\\n<h2 id=\\"方法\\" tabindex=\\"-1\\"><a class=\\"header-anchor\\" href=\\"#方法\\" aria-hidden=\\"true\\">#</a> 方法</h2>\\n<p>共有方法请参见其基类Material</p>\\n</iframe>","autoDesc":true}');export{e as data};
